import React from 'react';
import {ScrollView, Text, StyleSheet} from 'react-native';

export default function AutoPayScreen({bills=[]}){
  return (
    <ScrollView style={styles.screen}>
      <Text style={styles.title}>Auto-Pay Status</Text>
      <Text style={{marginTop:8, fontWeight:'600'}}>Upcoming:</Text>
      <Text>Light Bill – $150 – Will be paid on 15th</Text>
      <Text style={{marginTop:8, fontWeight:'600'}}>Last Payment:</Text>
      <Text>Phone Bill – $90 – Paid on 2nd</Text>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  screen:{flex:1,padding:16},
  title:{fontSize:20,fontWeight:'700'}
});
